  1	import { type ForwardedRef, forwardRef, type ReactNode, useImperativeHandle } from 'react';
  2	
  3	import {
  4	  MenuFooter,
  5	  type MenuToggleProps,
  6	  Select as PfSelect,
  7	  SelectList,
  8	  SelectOption,
  9	  type SelectProps,
 10	} from '@patternfly/react-core';
 11	import { isEmpty } from '@utils/helpers';
 12	
 13	import { DEFAULT_PLACEHOLDER } from '../utils/constants';
 14	import type { TypeaheadSelectOption } from '../utils/types';
 15	
 16	import { useMultiTypeaheadSelect } from './hooks/useMultiTypeaheadSelect';
 17	import MultiTypeaheadMenuToggle from './MultiTypeaheadMenuToggle';
 18	
 19	type MultiTypeaheadSelectProps = {
 20	  options: TypeaheadSelectOption[];
 21	  values?: (string | number)[];
 22	  onChange: (values: (string | number)[]) => void;
 23	  onCreateOption?: (createdValue: string) => void;
 24	  onInputChange?: (inputValue: string) => void;
 25	
 26	  allowClear?: boolean;
 27	  placeholder?: string;
 28	  isCreatable?: boolean;
 29	  createOptionMessage?: string | ((value: string) => string);
 30	  noOptionsMessage?: string;
 31	  emptyState?: ReactNode;
 32	  noResultsMessage?: string | ((filter: string) => string);
 33	  footer?: ReactNode;
 34	  isDisabled?: boolean;
 35	  toggleWidth?: string;
 36	  toggleProps?: Omit<MenuToggleProps, 'innerRef' | 'onClick' | 'isExpanded' | 'variant'>;
 37	  filterControls?: ReactNode;
 38	  maxSelections?: number;
 39	  testId?: string;
 40	  listboxId?: string;
 41	} & Omit<SelectProps, 'toggle' | 'onSelect' | 'selected' | 'isOpen'>;
 42	
 43	const MultiTypeaheadSelect = (
 44	  {
 45	    allowClear = false,
 46	    createOptionMessage,
 47	    emptyState,
 48	    filterControls,
 49	    footer,
 50	    isCreatable = false,
 51	    isDisabled = false,
 52	    listboxId,
 53	    maxSelections,
 54	    noOptionsMessage,
 55	    noResultsMessage,
 56	    onChange,
 57	    onCreateOption,
 58	    onInputChange,
 59	    options = [],
 60	    placeholder = DEFAULT_PLACEHOLDER,
 61	    testId,
 62	    toggleProps,
 63	    toggleWidth,
 64	    values = [],
 65	    ...selectProps
 66	  }: MultiTypeaheadSelectProps,
 67	  ref: ForwardedRef<HTMLInputElement>,
 68	) => {
 69	  const {
 70	    activeItemId,
 71	    displayOptions,
 72	    focusedItemIndex,
 73	    handleSelect,
 74	    inputRef,
 75	    inputValue,
 76	    isFiltering,
 77	    isOpen,
 78	    listboxId: listboxIdResolved,
 79	    onChipRemove,
 80	    onClearAll,
 81	    onInputClick,
 82	    onInputKeyDown,
 83	    onInputValueChange,
 84	    onOpenChange,
 85	    onToggleClick,
 86	    selectedOptions,
 87	    setIsOpen,
 88	  } = useMultiTypeaheadSelect({
 89	    createOptionMessage,
 90	    isCreatable,
 91	    listboxId,
 92	    maxSelections,
 93	    noOptionsMessage,
 94	    noResultsMessage,
 95	    onChange,
 96	    onCreateOption,
 97	    onInputChange,
 98	    options,
 99	    values,
100	  });
101	
102	  useImperativeHandle(ref, () => inputRef.current!, [inputRef]);
103	
104	  return (
105	    <PfSelect
106	      id="multi-create-typeahead-select"
107	      isOpen={isOpen}
108	      selected={values}
109	      onSelect={(_event, selection) => {
110	        handleSelect(selection);
111	      }}
112	      onOpenChange={onOpenChange}
113	      toggle={(toggleRef) => (
114	        <MultiTypeaheadMenuToggle
115	          toggleRef={toggleRef}
116	          inputRef={inputRef}
117	          placeholder={placeholder}
118	          isDisabled={isDisabled}
119	          isOpen={isOpen}
120	          toggleWidth={toggleWidth}
121	          allowClear={allowClear}
122	          selectedOptions={selectedOptions}
123	          isFiltering={isFiltering}
124	          inputValue={inputValue}
125	          onInputChange={onInputChange}
126	          onClearAll={onClearAll}
127	          onToggleClick={onToggleClick}
128	          onInputValueChange={onInputValueChange}
129	          onChipRemove={onChipRemove}
130	          toggleProps={toggleProps}
131	          testId={testId}
132	          onInputClick={onInputClick}
133	          onInputKeyDown={onInputKeyDown}
134	          activeItemId={activeItemId}
135	          listboxId={listboxIdResolved}
136	        />
137	      )}
138	      shouldFocusFirstItemOnOpen={false}
139	      {...selectProps}
140	    >
141	      {isEmpty(options) && emptyState ? (
142	        emptyState
143	      ) : (
144	        <>
145	          {filterControls}
146	          <SelectList id={listboxIdResolved} isAriaMultiselectable>
147	            {displayOptions.map((option, index) => {
148	              const { testId: optionTestId, ...restOptionProps } = option.optionProps ?? {};
149	              return (
150	                <SelectOption
151	                  key={String(option.value)}
152	                  id={String(option.value)} // optional: createItemId if you want stable IDs
153	                  isFocused={focusedItemIndex === index}
154	                  value={option.value}
155	                  data-testid={optionTestId}
156	                  {...restOptionProps}
157	                >
158	                  {option.content}
159	                </SelectOption>
160	              );
161	            })}
162	          </SelectList>
163	          {footer && (
164	            <MenuFooter
165	              onClick={() => {
166	                setIsOpen(false);
167	              }}
168	            >
169	              {footer}
170	            </MenuFooter>
171	          )}
172	        </>
173	      )}
174	    </PfSelect>
175	  );
176	};
177	
178	export default forwardRef(MultiTypeaheadSelect);

